import React from 'react';
import { useNavigate } from 'react-router-dom';
import { Store, PlusCircle, ShoppingBag } from 'lucide-react';

const Home = ({ isLoggedIn, userRole }) => {
  const navigate = useNavigate();

  // VISTA PARA EL VENDEDOR: Gestión y Negocios
  if (isLoggedIn && userRole === 'vendedor') {
    return (
      <div style={containerVendedor}>
        <div style={heroVendedor}>
          <h1>Bienvenido a tu Panel de Ventas</h1>
          <p>Gestiona tus sucursales y publica nuevas ofertas para tus clientes.</p>
          <div style={buttonGroup}>
            <button onClick={() => navigate('/dashboard')} style={btnPrimary}>
              <Store size={20} /> Ver Mis Locales
            </button>
            <button onClick={() => navigate('/dashboard')} style={btnSecondary}>
              <PlusCircle size={20} /> Nueva Sucursal
            </button>
          </div>
        </div>
        {/* Aquí podrías poner estadísticas rápidas o tips de venta */}
      </div>
    );
  }

  // VISTA PARA CLIENTE O VISITANTE: Buscador de Ofertas (Tu diseño original bello)
  return (
    <div style={containerPublico}>
      {/* SECCIÓN HERO CON TU IMAGEN DE FONDO */}
      <div style={heroPublico}>
        <div style={overlay}>
          <h1 style={titleStyle}>Encontrá todo lo que buscás <br/> <span>al mejor precio</span></h1>
          
          <div style={searchGlass}>
            <input type="text" placeholder="¿Qué buscás hoy?" style={inputStyle} />
            <button style={btnSearch}>Buscar</button>
          </div>
        </div>
      </div>

      {/* Solo mostramos los filtros si NO es vendedor */}
      <div style={filterSection}>
        {/* Tus botones de zonas: Barrio Norte, Barrio Sur, etc. */}
      </div>
    </div>
  );
};

// Estilos rápidos para diferenciar
const containerVendedor = { padding: '100px 8%', textAlign: 'center', background: '#f8fafc', minHeight: '80vh' };
const heroVendedor = { maxWidth: '800px', margin: '0 auto', background: 'white', padding: '50px', borderRadius: '20px', boxShadow: '0 10px 30px rgba(0,0,0,0.05)' };
const buttonGroup = { display: 'flex', gap: '20px', justifyContent: 'center', marginTop: '30px' };
const btnPrimary = { background: '#e67e22', color: 'white', border: 'none', padding: '15px 30px', borderRadius: '12px', cursor: 'pointer', display: 'flex', alignItems: 'center', gap: '10px', fontWeight: 'bold' };
const btnSecondary = { ...btnPrimary, background: '#1e293b' };

// ... (mantener tus estilos de Hero público)
